   177→/// Thread-safe collision manager for handling all collision events
   178→pub struct CollisionManager {
   179→    modules: Arc<Mutex<HashMap<ObjectID, Vec<Box<dyn CollideModule>>>>>,
   180→}
   181→
   182→impl CollisionManager {
   183→    pub fn new() -> Self {
   184→        Self {
   185→            modules: Arc::new(Mutex::new(HashMap::new())),
   186→        }
   187→    }
   188→
   189→    pub fn register_collide_module(&self, object_id: ObjectID, module: Box<dyn CollideModule>) -> Result<(), CollisionError> {
   190→        let mut modules = self.modules.lock().map_err(|e| 
   191→            CollisionError::InvalidObject(format!("Failed to acquire lock: {}", e))
   192→        )?;
   193→        
   194→        modules.entry(object_id).or_insert_with(Vec::new).push(module);
   195→        Ok(())
   196→    }
   197→
   198→    pub fn handle_collision(&self, object_id: ObjectID, other: Option<&dyn GameObject>, loc: &Coord3D, normal: &Coord3D) -> Result<(), CollisionError> {
   199→        let mut modules = self.modules.lock().map_err(|e| 
   200→            CollisionError::InvalidObject(format!("Failed to acquire lock: {}", e))
   201→        )?;
   202→        
   203→        if let Some(object_modules) = modules.get_mut(&object_id) {
   204→            for module in object_modules.iter_mut() {
   205→                module.on_collide(other, loc, normal)?;
   206→            }
   207→        }
   208→        
   209→        Ok(())
   210→    }
   211→
   212→    pub fn unregister_object(&self, object_id: ObjectID) -> Result<(), CollisionError> {
   213→        let mut modules = self.modules.lock().map_err(|e| 
   214→            CollisionError::InvalidObject(format!("Failed to acquire lock: {}", e))
   215→        )?;
   216→        
   217→        modules.remove(&object_id);
   218→        Ok(())
   219→    }
   220→}
   221→
   222→impl Default for CollisionManager {
   223→    fn default() -> Self {
   224→        Self::new()
   225→    }
   226→}
   227→
   228→/// Global collision manager instance
   229→lazy_static::lazy_static! {
   230→    pub static ref COLLISION_MANAGER: CollisionManager = CollisionManager::new();
   231→}
