   208→/// Fire Weapon Collide Module
   209→/// 
   210→/// This module fires a weapon at anything that collides with the owning object.
   211→/// It can be configured to fire once or repeatedly, and can have status requirements.
   212→pub struct FireWeaponCollide {
   213→    object_id: ObjectID,
   214→    module_data: FireWeaponCollideModuleData,
   215→    collide_weapon: Option<Box<dyn Weapon>>,
   216→    ever_fired: bool,
   217→    version: u32,
   218→}
   219→
   220→impl FireWeaponCollide {
   221→    /// Create a new FireWeaponCollide instance
   222→    /// 
   223→    /// # Arguments
   224→    /// * `object_id` - The ID of the object this module belongs to
   225→    /// * `module_data` - Configuration data for the fire weapon collision behavior
   226→    pub fn new(object_id: ObjectID, module_data: FireWeaponCollideModuleData) -> Result<Self, CollisionError> {
   227→        let weapon_store = WEAPON_STORE.lock().map_err(|e|
   228→            CollisionError::InvalidObject(format!("Failed to acquire weapon store lock: {}", e))
   229→        )?;
   230→        
   231→        let collide_weapon = weapon_store.allocate_new_weapon(
   232→            &module_data.collide_weapon_template,
   233→            WeaponType::Primary
   234→        );
   235→        
   236→        Ok(Self {
   237→            object_id,
   238→            module_data,
   239→            collide_weapon: Some(collide_weapon),
   240→            ever_fired: false,
   241→            version: 1,
   242→        })
   243→    }
   244→
   245→    /// Get the fire weapon collide module data
   246→    pub fn get_fire_weapon_collide_module_data(&self) -> &FireWeaponCollideModuleData {
   247→        &self.module_data
   248→    }
   249→
   250→    /// Check if the weapon should fire based on status and configuration
   251→    /// 
   252→    /// # Arguments
   253→    /// * `owner` - The object that owns this collision module
   254→    pub fn should_fire_weapon(&self, owner: &dyn GameObject) -> bool {
   255→        let status = owner.get_status_bits();
   256→        
   257→        // We need all required status bits or else we fail
   258→        if !status.test_for_all(self.module_data.required_status) {
   259→            return false;
   260→        }
   261→        
   262→        // If we have any forbidden status bits, then fail
   263→        if status.test_for_any(self.module_data.forbidden_status) {
   264→            return false;
   265→        }
   266→        
   267→        // If we can only fire once and have already fired, fail
   268→        if self.ever_fired && self.module_data.fire_once {
   269→            return false;
   270→        }
   271→        
   272→        true
   273→    }
   274→
   275→    /// Get the current version of this module for serialization
   276→    pub fn get_version(&self) -> u32 {
   277→        self.version
   278→    }
   279→
   280→    /// Serialize this module's state
   281→    pub fn serialize<T: crate::object::collide::crate_collide::shroud_crate_collide::Serialize>(&self, xfer: &mut T) -> Result<(), CollisionError> {
   282→        xfer.write_version(self.version)
   283→            .map_err(|e| CollisionError::InvalidObject(format!("Serialization failed: {}", e)))?;
   284→        
   285→        // In a full implementation, would serialize weapon state and ever_fired flag
   286→        
   287→        Ok(())
   288→    }
   289→
   290→    /// Deserialize this module's state
   291→    pub fn deserialize<T: crate::object::collide::crate_collide::shroud_crate_collide::Deserialize>(&mut self, xfer: &mut T) -> Result<(), CollisionError> {
   292→        let version = xfer.read_version()
   293→            .map_err(|e| CollisionError::InvalidObject(format!("Deserialization failed: {}", e)))?;
   294→        
   295→        if version != self.version {
   296→            return Err(CollisionError::InvalidObject(
   297→                format!("Version mismatch: expected {}, got {}", self.version, version)
   298→            ));
   299→        }
   300→        
   301→        // In a full implementation, would deserialize weapon state and ever_fired flag
   302→        
   303→        Ok(())
   304→    }
   305→
   306→    /// Compute CRC for this module's state
   307→    pub fn compute_crc(&self) -> u32 {
   308→        let mut crc = 0u32;
   309→        crc ^= self.version;
   310→        crc ^= if self.ever_fired { 1 } else { 0 };
   311→        crc ^= if self.module_data.fire_once { 2 } else { 0 };
   312→        crc ^= self.module_data.required_status.0 as u32;
   313→        crc ^= self.module_data.forbidden_status.0 as u32;
   314→        crc
   315→    }
   316→
   317→    /// Load post-processing after deserialization
   318→    pub fn load_post_process(&mut self) -> Result<(), CollisionError> {
   319→        // Perform any weapon-specific post-processing here
   320→        Ok(())
   321→    }
   322→}
