   332→impl CollideModule for FireWeaponCollide {
   333→    fn on_collide(&mut self, other: Option<&dyn GameObject>, _loc: &Coord3D, _normal: &Coord3D) -> Result<(), CollisionError> {
   334→        // Don't shoot the ground
   335→        let other_obj = match other {
   336→            Some(obj) => obj,
   337→            None => return Ok(()), // Collision with ground, do nothing
   338→        };
   339→        
   340→        // Create a mock owner object - in real implementation would have proper owner reference
   341→        let mock_owner = MockOwnerGameObject { id: self.object_id };
   342→        
   343→        // This will fire at the target every frame, because multiple objects could be
   344→        // colliding and we want to hurt them all. Another solution would be to keep
   345→        // a map of object IDs and delays for each individually.
   346→        if self.should_fire_weapon(&mock_owner) {
   347→            if let Some(ref mut weapon) = self.collide_weapon {
   348→                weapon.load_ammo_now(&mock_owner)
   349→                    .map_err(|e| CollisionError::InvalidObject(format!("Failed to load ammo: {}", e)))?;
   350→                
   351→                weapon.fire_weapon(&mock_owner, other_obj)
   352→                    .map_err(|e| CollisionError::InvalidObject(format!("Failed to fire weapon: {}", e)))?;
   353→                
   354→                self.ever_fired = true;
   355→            } else {
   356→                return Err(CollisionError::InvalidObject("No collision weapon available".to_string()));
   357→            }
   358→        }
   359→        
   360→        Ok(())
   361→    }
   362→
   363→    fn would_like_to_collide_with(&self, _other: &dyn GameObject) -> bool {
   364→        // Fire weapon collide modules generally want to collide with everything
   365→        true
   366→    }
